class SharedAutonomy:
    def __init__(self, conf_threshold=0.7):
        self.threshold = conf_threshold
        self.in_human_control = False

    def cmd(self, robot_cmd, robot_conf, human_cmd):
        if robot_conf >= self.threshold and not self.in_human_control:
            return robot_cmd, 'AUTO'
        # Trigger handoff
        if not self.in_human_control:
            self.notify_human('Confidence low - please take over')
            self.in_human_control = True
        return human_cmd, 'HUMAN'

    def release(self):
        self.in_human_control = False
